import torch
import torch.nn as nn
import math
from torch.utils.cpp_extension import load_inline

# Define the fused CUDA kernel for matmul + sigmoid + sum
fused_matmul_sigmoid_sum_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <math.h>

template<typename T>
__device__ T warpReduceSum(T val) {
    for (int offset = 16; offset > 0; offset /= 2) {
        val += __shfl_down_sync(0xffffffff, val, offset);
    }
    return val;
}

template<typename T>
__device__ T blockReduceSum(T val) {
    static __shared__ T shared[32];
    int lane = threadIdx.x % 32;
    int wid = threadIdx.x / 32;

    val = warpReduceSum(val);

    if (lane == 0) {
        shared[wid] = val;
    }
    __syncthreads();

    val = (threadIdx.x < blockDim.x / 32) ? shared[lane] : T(0);

    if (wid == 0) {
        val = warpReduceSum(val);
    }

    return val;
}

template<typename T>
__device__ T sigmoid_device(T x) {
    return T(1.0) / (T(1.0) + expf(-x));
}

template<typename T>
__global__ void fused_matmul_sigmoid_sum_kernel(
    const T* __restrict__ input,
    const T* __restrict__ weight,
    const T* __restrict__ bias,
    T* __restrict__ output,
    int batch_size,
    int input_size,
    int hidden_size) {

    int batch_idx = blockIdx.x;
    if (batch_idx >= batch_size) return;

    const T* input_row = input + batch_idx * input_size;
    T thread_sum = T(0);

    // Each thread handles multiple hidden units for better utilization
    for (int hidden_idx = threadIdx.x; hidden_idx < hidden_size; hidden_idx += blockDim.x) {
        const T* weight_row = weight + hidden_idx * input_size;
        T dot_product = T(0);

        // Compute dot product
        for (int i = 0; i < input_size; ++i) {
            dot_product += input_row[i] * weight_row[i];
        }

        // Add bias and apply sigmoid
        dot_product += bias[hidden_idx];
        dot_product = sigmoid_device(dot_product);

        thread_sum += dot_product;
    }

    // Reduce across all threads in the block
    thread_sum = blockReduceSum(thread_sum);

    if (threadIdx.x == 0) {
        output[batch_idx] = thread_sum;
    }
}

torch::Tensor fused_matmul_sigmoid_sum_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias) {

    int batch_size = input.size(0);
    int input_size = input.size(1);
    int hidden_size = weight.size(0);

    auto output = torch::zeros({batch_size, 1}, input.options());

    // Configure kernel launch
    dim3 blocks(batch_size);
    dim3 threads(256);  // Optimal for most GPUs

    AT_DISPATCH_FLOATING_TYPES(input.scalar_type(), "fused_matmul_sigmoid_sum", ([&] {
        fused_matmul_sigmoid_sum_kernel<scalar_t><<<blocks, threads>>>(
            input.data_ptr<scalar_t>(),
            weight.data_ptr<scalar_t>(),
            bias.data_ptr<scalar_t>(),
            output.data_ptr<scalar_t>(),
            batch_size,
            input_size,
            hidden_size);
    }));

    return output;
}
"""

fused_matmul_sigmoid_sum_cpp_source = """
torch::Tensor fused_matmul_sigmoid_sum_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias);
"""

# Compile the inline CUDA code
fused_matmul_sigmoid_sum = load_inline(
    name="fused_matmul_sigmoid_sum",
    cpp_sources=fused_matmul_sigmoid_sum_cpp_source,
    cuda_sources=fused_matmul_sigmoid_sum_source,
    functions=["fused_matmul_sigmoid_sum_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=[""],
    with_cuda=True
)

class ModelNew(nn.Module):
    """
    Optimized model with fused matmul + sigmoid + sum operation.
    """
    def __init__(self, input_size, hidden_size):
        super(ModelNew, self).__init__()
        self.input_size = input_size
        self.hidden_size = hidden_size

        # Initialize parameters like nn.Linear
        self.weight = nn.Parameter(torch.Tensor(hidden_size, input_size))
        self.bias = nn.Parameter(torch.Tensor(hidden_size))

        # Initialize weights
        self.reset_parameters()

        # Store the fused operation
        self.fused_op = fused_matmul_sigmoid_sum

    def reset_parameters(self):
        nn.init.kaiming_uniform_(self.weight, a=math.sqrt(5))
        if self.bias is not None:
            fan_in, _ = nn.init._calculate_fan_in_and_fan_out(self.weight)
            bound = 1 / math.sqrt(fan_in) if fan_in > 0 else 0
            nn.init.uniform_(self.bias, -bound, bound)

    def forward(self, x):
        """
        Args:
            x: Input tensor of shape (batch_size, input_size).

        Returns:
            Output tensor of shape (batch_size, 1).
        """
        return self.fused_op.fused_matmul_sigmoid_sum_cuda(x, self.weight, self.bias)

